import React, { useState, useEffect, useRef } from 'react';
import { 
  LayoutDashboard, FolderKanban, Users, 
  Plus, Edit2, Trash2, X, Newspaper, Briefcase, Camera, 
  LayoutList, Facebook, Instagram, Linkedin, Calendar, Sparkles, Loader2
} from 'lucide-react';
import { getDb, saveDb } from '../services/mockDb';
import { Project, ApplicationStatus, ProjectStatus, NewsItem, StaffMember, VolunteerApplication } from '../types';
import { generateProjectPitch } from '../services/gemini';

const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'projects' | 'applications' | 'news' | 'staff'>('overview');
  const [db, setDb] = useState(getDb());

  const [showProjectModal, setShowProjectModal] = useState(false);
  const [showNewsModal, setShowNewsModal] = useState(false);
  const [showStaffModal, setShowStaffModal] = useState(false);
  const [isAiGenerating, setIsAiGenerating] = useState(false);

  const [editingProject, setEditingProject] = useState<Project | null>(null);
  const [editingStaff, setEditingStaff] = useState<StaffMember | null>(null);

  const staffImageRef = useRef<HTMLInputElement>(null);
  const projectImageRef = useRef<HTMLInputElement>(null);

  const [staffForm, setStaffForm] = useState({
    name: '', 
    role: '', 
    category: 'Stafi Aktual', 
    bio: '', 
    image: '', 
    socials: { facebook: '', instagram: '', linkedin: '' }
  });

  const [projectForm, setProjectForm] = useState({
    title: '',
    description: '',
    longDescription: '',
    startDate: '',
    endDate: '',
    status: ProjectStatus.Active,
    image: '',
    volunteerCount: 0
  });

  const staffCategories = [
    'Kuvendi i Anëtarëve',
    'Bordi i Drejtorëve',
    'Drejtor Ekzekutiv',
    'Stafi Aktual',
    'Vullnetarët'
  ];

  useEffect(() => {
    setDb(getDb());
  }, []);

  const handleFileRead = (file: File): Promise<string> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onloadend = () => resolve(reader.result as string);
      reader.readAsDataURL(file);
    });
  };

  const handleOpenStaffModal = (member?: StaffMember) => {
    if (member) {
      setEditingStaff(member);
      setStaffForm({
        name: member.name,
        role: member.role,
        category: member.category || 'Stafi Aktual',
        bio: member.bio || '',
        image: member.image || '',
        socials: {
          facebook: member.socials?.facebook || '',
          instagram: member.socials?.instagram || '',
          linkedin: member.socials?.linkedin || '',
        }
      });
    } else {
      setEditingStaff(null);
      setStaffForm({ 
        name: '', 
        role: '', 
        category: 'Stafi Aktual', 
        bio: '', 
        image: '', 
        socials: { facebook: '', instagram: '', linkedin: '' } 
      });
    }
    setShowStaffModal(true);
  };

  const handleOpenProjectModal = (project?: Project) => {
    if (project) {
      setEditingProject(project);
      setProjectForm({
        title: project.title,
        description: project.description,
        longDescription: project.longDescription || '',
        startDate: project.startDate,
        endDate: project.endDate,
        status: project.status,
        image: project.image,
        volunteerCount: project.volunteerCount
      });
    } else {
      setEditingProject(null);
      setProjectForm({
        title: '',
        description: '',
        longDescription: '',
        startDate: new Date().toISOString().split('T')[0],
        endDate: '',
        status: ProjectStatus.Active,
        image: '',
        volunteerCount: 0
      });
    }
    setShowProjectModal(true);
  };

  const handleSaveStaff = () => {
    if (!staffForm.name || !staffForm.role) return alert("Ju lutem plotësoni emrin dhe pozitën.");

    const newStaffMember: StaffMember = {
      id: editingStaff ? editingStaff.id : 's_' + Date.now(),
      name: staffForm.name,
      role: staffForm.role,
      category: staffForm.category,
      bio: staffForm.bio,
      image: staffForm.image || 'https://images.unsplash.com/photo-1550525811-e5869dd03032?auto=format&fit=crop&q=80&w=100',
      socials: staffForm.socials
    };

    const updatedStaff = editingStaff
      ? db.staff.map(s => s.id === editingStaff.id ? newStaffMember : s)
      : [...db.staff, newStaffMember];

    updateDb({ ...db, staff: updatedStaff });
    setShowStaffModal(false);
  };

  const handleSaveProject = () => {
    if (!projectForm.title || !projectForm.description) return alert("Ju lutem plotësoni titullin dhe përshkrimin.");

    const newProject: Project = {
      id: editingProject ? editingProject.id : 'p_' + Date.now(),
      ...projectForm,
      volunteerCount: projectForm.volunteerCount || 0,
      image: projectForm.image || 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?auto=format&fit=crop&q=80&w=800'
    };

    const updatedProjects = editingProject
      ? db.projects.map(p => p.id === editingProject.id ? newProject : p)
      : [...db.projects, newProject];

    updateDb({ ...db, projects: updatedProjects });
    setShowProjectModal(false);
  };

  const handleGenerateAiDescription = async () => {
    if (!projectForm.title) return alert("Ju lutem shkruani një titull për projektin së pari.");
    setIsAiGenerating(true);
    try {
      const pitch = await generateProjectPitch(projectForm.title, "rinia, Shala, Lipjan, komuniteti, edukim");
      setProjectForm(prev => ({ ...prev, description: pitch }));
    } catch (err) {
      alert("Gabim gjatë gjenerimit me AI.");
    } finally {
      setIsAiGenerating(false);
    }
  };

  const updateDb = (newDb: any) => {
    setDb(newDb);
    saveDb(newDb);
  };

  const deleteItem = (type: 'projects' | 'news' | 'staff', id: string) => {
    if (!confirm('A jeni të sigurt?')) return;
    const newData = { ...db, [type]: db[type].filter((item: any) => item.id !== id) };
    updateDb(newData);
  };

  const stats = [
    { label: 'Projekte', value: db.projects.length, icon: FolderKanban, color: 'bg-brand-pink' },
    { label: 'Aplikime', value: db.applications?.length || 0, icon: Users, color: 'bg-brand-cyan' },
    { label: 'Staff', value: db.staff.length, icon: Briefcase, color: 'bg-brand-blue' },
    { label: 'Lajme', value: db.news.length, icon: Newspaper, color: 'bg-brand-lime' },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      <aside className="w-full md:w-72 bg-brand-dark border-r border-slate-800 flex-shrink-0 text-white z-20">
        <div className="p-8 sticky top-0">
          <div className="flex items-center space-x-3 mb-10">
            <div className="w-8 h-8 rounded-full border-2 border-brand-pink flex items-center justify-center">
              <div className="w-3 h-3 bg-brand-pink rounded-full"></div>
            </div>
            <span className="text-sm font-black uppercase tracking-[0.2em]">ADMIN PANEL</span>
          </div>
          <nav className="space-y-2">
            {[
              { id: 'overview', icon: LayoutDashboard, label: 'Pasqyra' },
              { id: 'projects', icon: FolderKanban, label: 'Projektet' },
              { id: 'staff', icon: Briefcase, label: 'Stafi & Ekipi' },
              { id: 'news', icon: Newspaper, label: 'Lajmet' },
              { id: 'applications', icon: Users, label: 'Aplikimet' },
            ].map(item => (
              <button 
                key={item.id}
                onClick={() => setActiveTab(item.id as any)}
                className={`w-full flex items-center space-x-4 px-6 py-4 rounded-2xl transition-all font-bold uppercase text-[10px] tracking-widest ${activeTab === item.id ? 'bg-white/10 text-brand-pink shadow-lg' : 'text-slate-400 hover:bg-white/5 hover:text-white'}`}
              >
                <item.icon className="h-5 w-5" />
                <span>{item.label}</span>
              </button>
            ))}
          </nav>
        </div>
      </aside>

      <main className="flex-grow p-8 md:p-12 overflow-x-hidden">
        <div className="max-w-6xl mx-auto">

          {activeTab === 'overview' && (
            <div className="space-y-12 animate-in fade-in">
              <h1 className="text-4xl font-black text-brand-dark uppercase tracking-tight">Menaxhimi i VRSH</h1>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
                {stats.map((stat, i) => (
                  <div key={i} className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
                    <div className={`${stat.color} w-12 h-12 rounded-2xl text-white flex items-center justify-center mb-6`}>
                      <stat.icon className="h-6 w-6" />
                    </div>
                    <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.15em] mb-1">{stat.label}</p>
                    <p className="text-3xl font-black text-brand-dark">{stat.value}</p>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'projects' && (
            <div className="space-y-8 animate-in fade-in">
              <div className="flex items-center justify-between">
                <h1 className="text-3xl font-black text-brand-dark uppercase">Projektet e Organizatës</h1>
                <button onClick={() => handleOpenProjectModal()} className="bg-brand-pink text-white px-8 py-3 rounded-full font-black uppercase text-[10px] tracking-widest flex items-center shadow-lg shadow-brand-pink/20">
                  <Plus className="h-4 w-4 mr-2" /> Shto Projekt
                </button>
              </div>
              <div className="bg-white rounded-[2rem] border border-slate-100 overflow-hidden shadow-sm">
                <table className="w-full text-left">
                  <thead className="bg-slate-50/50 border-b border-slate-100">
                    <tr>
                      <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Titulli</th>
                      <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Statusi</th>
                      <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Periudha</th>
                      <th className="px-8 py-5 text-right">Veprimet</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {db.projects.map(p => (
                      <tr key={p.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-6">
                           <div className="flex items-center space-x-3">
                              <img src={p.image} className="w-10 h-10 rounded-xl object-cover bg-slate-100" />
                              <span className="font-bold text-sm line-clamp-1">{p.title}</span>
                           </div>
                        </td>
                        <td className="px-8 py-6">
                           <span className={`px-4 py-1.5 rounded-full text-[8px] font-black uppercase tracking-widest ${p.status === ProjectStatus.Active ? 'bg-brand-lime/10 text-brand-lime' : 'bg-slate-100 text-slate-400'}`}>
                             {p.status}
                           </span>
                        </td>
                        <td className="px-8 py-6">
                           <span className="text-[10px] font-bold text-slate-500">{p.startDate} - {p.endDate || '...'}</span>
                        </td>
                        <td className="px-8 py-6 text-right space-x-2">
                          <button onClick={() => handleOpenProjectModal(p)} className="p-2 text-slate-400 hover:text-brand-pink transition-colors"><Edit2 className="h-4 w-4" /></button>
                          <button onClick={() => deleteItem('projects', p.id)} className="p-2 text-slate-400 hover:text-red-500 transition-colors"><Trash2 className="h-4 w-4" /></button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'staff' && (
            <div className="space-y-8 animate-in fade-in">
              <div className="flex items-center justify-between">
                <h1 className="text-3xl font-black text-brand-dark uppercase">Stafi & Ekipi</h1>
                <button onClick={() => handleOpenStaffModal()} className="bg-brand-cyan text-white px-8 py-3 rounded-full font-black uppercase text-[10px] tracking-widest flex items-center shadow-lg shadow-brand-cyan/20">
                  <Plus className="h-4 w-4 mr-2" /> Shto Person
                </button>
              </div>
              <div className="bg-white rounded-[2rem] border border-slate-100 overflow-hidden shadow-sm">
                <table className="w-full text-left">
                  <thead className="bg-slate-50/50 border-b border-slate-100">
                    <tr>
                      <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Emri</th>
                      <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Kategoria</th>
                      <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pozita</th>
                      <th className="px-8 py-5 text-right">Veprimet</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {db.staff.map(s => (
                      <tr key={s.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-6 flex items-center space-x-3">
                           <img src={s.image} className="w-10 h-10 rounded-full object-cover bg-slate-100" />
                           <span className="font-bold text-sm">{s.name}</span>
                        </td>
                        <td className="px-8 py-6">
                           <span className="text-[10px] font-bold uppercase text-slate-400">{s.category}</span>
                        </td>
                        <td className="px-8 py-6">
                           <span className="text-[10px] font-black uppercase text-brand-pink">{s.role}</span>
                        </td>
                        <td className="px-8 py-6 text-right space-x-2">
                          <button onClick={() => handleOpenStaffModal(s)} className="p-2 text-slate-400 hover:text-brand-pink transition-colors"><Edit2 className="h-4 w-4" /></button>
                          <button onClick={() => deleteItem('staff', s.id)} className="p-2 text-slate-400 hover:text-red-500 transition-colors"><Trash2 className="h-4 w-4" /></button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Project Modal */}
      {showProjectModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-brand-dark/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-3xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
             <div className="p-10 border-b border-slate-100 flex items-center justify-between">
               <h2 className="text-2xl font-black text-brand-dark uppercase">{editingProject ? 'Edito Projektin' : 'Shto Projekt të Ri'}</h2>
               <button onClick={() => setShowProjectModal(false)}><X className="h-8 w-8 text-slate-300" /></button>
             </div>
             <div className="p-10 space-y-6 max-h-[70vh] overflow-y-auto custom-scrollbar">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400">Titulli i Projektit</label>
                  <input type="text" className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-brand-pink outline-none" value={projectForm.title} onChange={e => setProjectForm({...projectForm, title: e.target.value})} />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Data e Fillimit</label>
                    <input type="date" className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-brand-pink outline-none" value={projectForm.startDate} onChange={e => setProjectForm({...projectForm, startDate: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Data e Përfundimit</label>
                    <input type="date" className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-brand-pink outline-none" value={projectForm.endDate} onChange={e => setProjectForm({...projectForm, endDate: e.target.value})} />
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Statusi</label>
                    <select className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-brand-pink outline-none" value={projectForm.status} onChange={e => setProjectForm({...projectForm, status: e.target.value as ProjectStatus})}>
                      <option value={ProjectStatus.Active}>Aktive</option>
                      <option value={ProjectStatus.Completed}>E Përfunduar</option>
                      <option value={ProjectStatus.Upcoming}>Së Shpejti</option>
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Vullnetarë të Angazhuar</label>
                    <input type="number" className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-brand-pink outline-none" value={projectForm.volunteerCount} onChange={e => setProjectForm({...projectForm, volunteerCount: parseInt(e.target.value) || 0})} />
                  </div>
                </div>

                <div className="space-y-2 relative">
                   <div className="flex items-center justify-between">
                     <label className="text-[10px] font-black uppercase text-slate-400">Përshkrimi i Shkurtër</label>
                     <button 
                       onClick={handleGenerateAiDescription}
                       disabled={isAiGenerating}
                       className="text-[9px] font-black text-brand-orange uppercase flex items-center hover:opacity-80 disabled:opacity-50"
                     >
                       {isAiGenerating ? <Loader2 className="h-3 w-3 mr-1 animate-spin" /> : <Sparkles className="h-3 w-3 mr-1" />}
                       Gjenero me AI
                     </button>
                   </div>
                   <textarea rows={3} className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-medium focus:ring-2 focus:ring-brand-pink outline-none resize-none" value={projectForm.description} onChange={e => setProjectForm({...projectForm, description: e.target.value})} />
                </div>

                <div className="space-y-2">
                   <label className="text-[10px] font-black uppercase text-slate-400">Detajet e Projektit (Long Description)</label>
                   <textarea rows={5} className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-medium focus:ring-2 focus:ring-brand-pink outline-none resize-none" value={projectForm.longDescription} onChange={e => setProjectForm({...projectForm, longDescription: e.target.value})} />
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400">Imazhi Kryesor</label>
                  <div onClick={() => projectImageRef.current?.click()} className="cursor-pointer h-40 border-2 border-dashed border-slate-200 rounded-3xl flex items-center justify-center overflow-hidden bg-slate-50">
                    {projectForm.image ? <img src={projectForm.image} className="w-full h-full object-cover" /> : <div className="flex flex-col items-center"><Camera className="text-slate-300 mb-1" /><span className="text-[8px] font-black uppercase text-slate-400">Ngarko Imazh</span></div>}
                  </div>
                  <input type="file" hidden ref={projectImageRef} accept="image/*" onChange={async e => {
                    const input = e.target as HTMLInputElement;
                    const file = input.files?.[0];
                    if (file) setProjectForm({...projectForm, image: await handleFileRead(file)});
                  }} />
                </div>

                <button onClick={handleSaveProject} className="w-full py-5 bg-brand-pink text-white rounded-2xl font-black uppercase text-sm tracking-widest shadow-xl shadow-brand-pink/20">Ruaj Projektin</button>
             </div>
          </div>
        </div>
      )}

      {/* Staff Modal */}
      {showStaffModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-brand-dark/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden">
             <div className="p-10 border-b border-slate-100 flex items-center justify-between">
               <h2 className="text-2xl font-black text-brand-dark uppercase">{editingStaff ? 'Edito Personin' : 'Shto Person të Ri'}</h2>
               <button onClick={() => setShowStaffModal(false)}><X className="h-8 w-8 text-slate-300" /></button>
             </div>
             <div className="p-10 space-y-6 max-h-[70vh] overflow-y-auto custom-scrollbar">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Emri Mbiemri</label>
                    <input type="text" className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-brand-cyan outline-none" value={staffForm.name} onChange={e => setStaffForm({...staffForm, name: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Kategoria Organizative</label>
                    <select 
                      className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-brand-cyan outline-none" 
                      value={staffForm.category} 
                      onChange={e => setStaffForm({...staffForm, category: e.target.value})}
                    >
                      {staffCategories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                    </select>
                  </div>
                </div>

                <div className="space-y-2">
                   <label className="text-[10px] font-black uppercase text-slate-400">Pozita / Roli</label>
                   <input 
                      type="text" 
                      placeholder="P.sh. Asistente e Projekteve, Anëtar i Bordit..."
                      className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-brand-cyan outline-none" 
                      value={staffForm.role} 
                      onChange={e => setStaffForm({...staffForm, role: e.target.value})}
                   />
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400">Fotoja</label>
                  <div onClick={() => staffImageRef.current?.click()} className="cursor-pointer h-32 border-2 border-dashed border-slate-200 rounded-2xl flex items-center justify-center overflow-hidden bg-slate-50">
                    {staffForm.image ? <img src={staffForm.image} className="w-full h-full object-cover" /> : <div className="flex flex-col items-center"><Camera className="text-slate-300 mb-1" /><span className="text-[8px] font-black uppercase text-slate-400">Ngarko Foto</span></div>}
                  </div>
                  <input type="file" hidden ref={staffImageRef} accept="image/*" onChange={async e => {
                    const input = e.target as HTMLInputElement;
                    const file = input.files?.[0];
                    if (file) setStaffForm({...staffForm, image: await handleFileRead(file)});
                  }} />
                </div>

                <div className="space-y-2">
                   <label className="text-[10px] font-black uppercase text-slate-400">Bio / Përshkrimi</label>
                   <textarea 
                      rows={3}
                      placeholder="Shkruani një përshkrim të shkurtër për këtë person..."
                      className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-medium focus:ring-2 focus:ring-brand-cyan outline-none resize-none" 
                      value={staffForm.bio} 
                      onChange={e => setStaffForm({...staffForm, bio: e.target.value})}
                   />
                </div>

                <div className="space-y-4 pt-4 border-t border-slate-100">
                   <label className="text-[10px] font-black uppercase text-slate-400">Rrjetet Sociale (Linqet)</label>
                   <div className="grid grid-cols-1 gap-4">
                      <div className="relative">
                        <Facebook className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                        <input type="text" placeholder="Linku i Facebook" className="w-full pl-12 pr-6 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs outline-none focus:ring-2 focus:ring-brand-pink" value={staffForm.socials.facebook} onChange={e => setStaffForm({...staffForm, socials: {...staffForm.socials, facebook: e.target.value}})} />
                      </div>
                      <div className="relative">
                        <Instagram className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                        <input type="text" placeholder="Linku i Instagram" className="w-full pl-12 pr-6 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs outline-none focus:ring-2 focus:ring-brand-pink" value={staffForm.socials.instagram} onChange={e => setStaffForm({...staffForm, socials: {...staffForm.socials, instagram: e.target.value}})} />
                      </div>
                      <div className="relative">
                        <Linkedin className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                        <input type="text" placeholder="Linku i LinkedIn" className="w-full pl-12 pr-6 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs outline-none focus:ring-2 focus:ring-brand-pink" value={staffForm.socials.linkedin} onChange={e => setStaffForm({...staffForm, socials: {...staffForm.socials, linkedin: e.target.value}})} />
                      </div>
                   </div>
                </div>

                <button onClick={handleSaveStaff} className="w-full py-5 bg-brand-cyan text-white rounded-2xl font-black uppercase text-sm tracking-widest shadow-xl shadow-brand-cyan/20">Ruaj Të Dhënat</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useRef } from 'react';
import { 
  LayoutDashboard, FolderKanban, Users, 
  Plus, Edit2, Trash2, X, Newspaper, Briefcase, Camera, 
  Facebook, Instagram, Linkedin, Calendar, Sparkles, Loader2,
  CheckCircle, XCircle, Eye, FileText, ExternalLink
} from 'lucide-react';
import { getDb, saveDb } from '../services/mockDb';
import { Project, ApplicationStatus, ProjectStatus, NewsItem, StaffMember, VolunteerApplication } from '../types';
import { GoogleGenAI } from "@google/genai";

const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'projects' | 'applications' | 'news' | 'staff'>('overview');
  const [db, setDb] = useState(getDb());

  const [showProjectModal, setShowProjectModal] = useState(false);
  const [showNewsModal, setShowNewsModal] = useState(false);
  const [showStaffModal, setShowStaffModal] = useState(false);
  const [showAppDetails, setShowAppDetails] = useState<VolunteerApplication | null>(null);
  const [isAiGenerating, setIsAiGenerating] = useState(false);

  const [editingProject, setEditingProject] = useState<Project | null>(null);
  const [editingStaff, setEditingStaff] = useState<StaffMember | null>(null);
  const [editingNews, setEditingNews] = useState<NewsItem | null>(null);

  const staffImageRef = useRef<HTMLInputElement>(null);
  const projectImageRef = useRef<HTMLInputElement>(null);

  const [staffForm, setStaffForm] = useState({
    name: '', role: '', category: 'Stafi Aktual', bio: '', image: '', 
    socials: { facebook: '', instagram: '', linkedin: '' }
  });

  const [projectForm, setProjectForm] = useState({
    title: '', description: '', longDescription: '', startDate: '', endDate: '',
    status: ProjectStatus.Active, image: '', volunteerCount: 0
  });

  const [newsForm, setNewsForm] = useState({
    title: '', content: '', datePosted: '', category: 'Lajmet e fundit', fileUrl: ''
  });

  useEffect(() => {
    setDb(getDb());
  }, []);

  const updateDb = (newDb: any) => {
    setDb(newDb);
    saveDb(newDb);
  };

  const handleFileRead = (file: File): Promise<string> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onloadend = () => resolve(reader.result as string);
      reader.readAsDataURL(file);
    });
  };

  // AI Generation Function
  const generateWithAi = async (promptType: 'project' | 'news') => {
    const title = promptType === 'project' ? projectForm.title : newsForm.title;
    if (!title) return alert("Ju lutem shkruani një titull së pari.");

    setIsAiGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = promptType === 'project' 
        ? `Shkruaj një përshkrim profesional dhe frymëzues për një projekt të OJQ-së VRSH me titull "${title}". Përfshi rëndësinë për rininë e fshatit Shalë dhe Lipjanin. Rreth 100 fjalë.`
        : `Shkruaj një artikull lajmesh formal për organizatën VRSH me titull "${title}". Përdor gjuhë gazetareske shqipe, përmend rëndësinë e aktivitetit dhe ndikimin te komuniteti. Rreth 150 fjalë.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
      });

      const result = response.text || "";
      if (promptType === 'project') setProjectForm(prev => ({ ...prev, description: result }));
      else setNewsForm(prev => ({ ...prev, content: result }));
    } catch (err) {
      alert("Gabim gjatë gjenerimit me AI.");
    } finally {
      setIsAiGenerating(false);
    }
  };

  // Handlers for News
  const handleOpenNewsModal = (item?: NewsItem) => {
    if (item) {
      setEditingNews(item);
      setNewsForm({ ...item });
    } else {
      setEditingNews(null);
      setNewsForm({
        title: '', content: '', datePosted: new Date().toISOString().split('T')[0],
        category: 'Lajmet e fundit', fileUrl: ''
      });
    }
    setShowNewsModal(true);
  };

  const handleSaveNews = () => {
    if (!newsForm.title || !newsForm.content) return alert("Plotësoni titullin dhe përmbajtjen.");
    const newItem: NewsItem = { id: editingNews ? editingNews.id : 'n_' + Date.now(), ...newsForm };
    const updatedNews = editingNews ? db.news.map(n => n.id === editingNews.id ? newItem : n) : [...db.news, newItem];
    updateDb({ ...db, news: updatedNews });
    setShowNewsModal(false);
  };

  // Handlers for Applications
  const handleAppAction = (id: string, status: ApplicationStatus) => {
    const updatedApps = db.applications.map(app => app.id === id ? { ...app, status } : app);
    updateDb({ ...db, applications: updatedApps });
    if (showAppDetails?.id === id) setShowAppDetails({ ...showAppDetails, status });
  };

  const deleteItem = (type: 'projects' | 'news' | 'staff' | 'applications', id: string) => {
    if (!confirm('A jeni të sigurt?')) return;
    updateDb({ ...db, [type]: db[type].filter((item: any) => item.id !== id) });
