    const newS = { id: editingStaff ? editingStaff.id : 's_' + Date.now(), ...staffForm };
    const updated = editingStaff ? db.staff.map(s => s.id === editingStaff.id ? newS : s) : [...db.staff, newS];
    updateDb({ ...db, staff: updated });
    setShowStaffModal(false);
  };

  return (
