                  <h1 className="text-3xl font-black text-brand-dark uppercase">{t('admin.news')}</h1>
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Menaxhoni Lajmet dhe Raportet e VRSH</p>
