import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { getDb } from '../services/mockDb';
import { NewsItem } from '../types';
import { useLanguage } from '../context/LanguageContext';
import { Calendar, Tag, ArrowRight, Newspaper, Tv, FileText, Download, ExternalLink, Search } from 'lucide-react';

const News: React.FC = () => {
  const { category } = useParams<{ category: string }>();
  const [news, setNews] = useState<NewsItem[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const { t, language } = useLanguage();

  useEffect(() => {
    const db = getDb();
    let items = db.news || [];

    if (category) {
      const mapping: Record<string, string[]> = {
        'latest': ['Latest News', 'Lajmet e fundit'],
        'media': ['Media'],
        'reports': ['Reports', 'Raportet']
      };
      const dbCategories = mapping[category];
      if (dbCategories) {
        items = items.filter(n => dbCategories.includes(n.category));
      }
    }
    setNews(items);
  }, [category, language]);

  const filteredNews = news.filter(n => 
    n.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
    n.content.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const getTitle = () => {
    switch (category) {
      case 'media': return t('news.title.media');
      case 'latest': return t('news.title.latest');
      case 'reports': return t('news.title.reports');
      default: return t('news.title.all');
    }
  };

  const getIcon = (cat: string) => {
    if (cat === 'Media') return <Tv className="h-5 w-5 text-brand-orange" />;
    if (cat === 'Reports' || cat === 'Raportet') return <FileText className="h-5 w-5 text-brand-cyan" />;
    return <Newspaper className="h-5 w-5 text-brand-pink" />;
  };

  return (
    <div className="py-24 px-6 bg-slate-50 min-h-screen">
      <div className="max-w-5xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 mb-16">
          <div>
            <h1 className="text-5xl font-black text-brand-dark uppercase tracking-tighter mb-4">{getTitle()}</h1>
            <div className="h-1.5 w-24 bg-brand-pink rounded-full"></div>
          </div>

          <div className="relative group max-w-xs w-full">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 h-4 w-4 group-focus-within:text-brand-pink transition-colors" />
            <input 
              type="text" 
              placeholder={language === 'AL' ? "Kërko lajme..." : "Search news..."}
              className="w-full pl-12 pr-6 py-4 bg-white border border-slate-200 rounded-3xl text-sm font-bold outline-none focus:ring-2 focus:ring-brand-pink shadow-sm transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {filteredNews.length === 0 ? (
          <div className="bg-white p-20 rounded-[3.5rem] text-center border border-slate-100 shadow-sm animate-in fade-in">
            <Newspaper className="h-16 w-16 text-slate-100 mx-auto mb-6" />
            <p className="text-slate-400 font-black uppercase tracking-[0.2em] text-xs">{t('news.empty')}</p>
          </div>
        ) : (
          <div className="space-y-8">
            {filteredNews.map((item) => (
              <div key={item.id} className="bg-white p-8 md:p-10 rounded-[3.5rem] shadow-sm hover:shadow-2xl transition-all border border-slate-100 flex flex-col md:flex-row md:items-center gap-8 group animate-in slide-in-from-bottom-4">
                <div className="w-16 h-16 md:w-20 md:h-20 bg-slate-50 rounded-[1.5rem] flex items-center justify-center flex-shrink-0 group-hover:bg-brand-dark group-hover:text-white transition-all duration-500 shadow-inner">
                  {getIcon(item.category)}
                </div>
                <div className="flex-grow">
                  <div className="flex flex-wrap items-center gap-4 mb-4">
                    <span className="flex items-center text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50 px-3 py-1.5 rounded-full">
                      <Calendar className="h-3 w-3 mr-2" />
                      {item.datePosted}
                    </span>
                    <span className={`px-3 py-1.5 text-[9px] font-black uppercase tracking-widest rounded-full ${
                      item.category === 'Reports' ? 'bg-brand-cyan/10 text-brand-cyan' :
                      item.category === 'Media' ? 'bg-brand-orange/10 text-brand-orange' : 'bg-brand-pink/10 text-brand-pink'
                    }`}>
                      {item.category === 'Reports' ? t('news.title.reports') : (item.category === 'Media' ? t('news.title.media') : t('news.title.latest'))}
                    </span>
                  </div>
                  <h3 className="text-2xl md:text-3xl font-black text-brand-dark uppercase leading-tight mb-3 group-hover:text-brand-pink transition-colors">
                    {item.title}
                  </h3>
                  <p className="text-slate-500 font-medium line-clamp-2 leading-relaxed text-sm md:text-base italic">
                    {item.content}
                  </p>

                  {item.fileUrl && (
                    <div className="flex gap-4 mt-8">
                      {(item.category === 'Reports' || item.category === 'Raportet') ? (
                        <a 
                          href={item.fileUrl} 
                          target="_blank"
                          rel="noopener noreferrer"
                          className="flex items-center space-x-3 bg-brand-cyan text-white px-8 py-3 rounded-full font-black uppercase text-[10px] tracking-widest hover:bg-brand-dark transition-all shadow-lg shadow-brand-cyan/20"
                        >
                          <Download className="h-4 w-4" />
                          <span>{t('news.download')}</span>
                        </a>
                      ) : (
                        <a 
                          href={item.fileUrl} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="flex items-center space-x-3 bg-brand-orange text-white px-8 py-3 rounded-full font-black uppercase text-[10px] tracking-widest hover:bg-brand-dark transition-all shadow-lg shadow-brand-orange/20"
                        >
                          <ExternalLink className="h-4 w-4" />
                          <span>{t('news.source')}</span>
                        </a>
                      )}
                    </div>
                  )}
                </div>
                {(!item.fileUrl) && (
                  <button className="hidden md:flex items-center justify-center w-14 h-14 bg-slate-50 rounded-full group-hover:bg-brand-pink group-hover:text-white transition-all shadow-sm">
                    <ArrowRight className="h-6 w-6" />
                  </button>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

