      {/* Mobile Menu */}
      <div className={`md:hidden fixed inset-0 z-[90] bg-white transition-all duration-500 ${isOpen ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-full pointer-events-none'}`}>
        <div className="flex flex-col items-center justify-center h-full space-y-8 px-8">
           <Link to="/" className="text-4xl font-black uppercase tracking-tighter text-brand-dark" onClick={() => setIsOpen(false)}>{t('nav.home')}</Link>
           <Link to="/about/mission" className="text-4xl font-black uppercase tracking-tighter text-brand-pink" onClick={() => setIsOpen(false)}>{t('nav.about')}</Link>
           <Link to="/projects" className="text-4xl font-black uppercase tracking-tighter text-brand-cyan" onClick={() => setIsOpen(false)}>{t('nav.projects')}</Link>
           <Link to="/derdo" className="text-4xl font-black uppercase tracking-tighter text-brand-orange" onClick={() => setIsOpen(false)}>{t('nav.derdo')}</Link>
           <Link to="/join" className="px-12 py-5 bg-brand-lime text-white rounded-full text-xl font-black uppercase tracking-widest shadow-2xl" onClick={() => setIsOpen(false)}>{t('nav.join')}</Link>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, LogOut, LogIn, ChevronDown, UserPlus, MessageSquare, LayoutDashboard, X } from 'lucide-react';
import { User, UserRole } from '../types';
import { useLanguage } from '../context/LanguageContext';

interface NavbarProps {
  user: User | null;
  onLogout: () => void;
}

const VizioniLogo = () => (
  <div className="relative flex items-center justify-center w-10 h-10 group">
    <div className="absolute inset-0 rounded-xl border border-slate-200 group-hover:border-transparent transition-all duration-500 rotate-45 group-hover:rotate-90"></div>
    <div className="absolute inset-0 rounded-xl border border-transparent transition-all duration-700 -rotate-12 group-hover:rotate-45"
         style={{ borderTopColor: '#e11d74', borderRightColor: '#f39237', borderBottomColor: '#95d03a', borderLeftColor: '#00adb5' }}></div>
    <div className="w-2 h-2 bg-brand-dark rounded-full shadow-lg group-hover:scale-125 transition-transform"></div>
  </div>
);

const Navbar: React.FC<NavbarProps> = ({ user, onLogout }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [activeDropdown, setActiveDropdown] = useState<string | null>(null);
  const location = useLocation();
  const { t } = useLanguage();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const isActive = (path: string) => location.pathname === path || (path !== '/' && location.pathname.startsWith(path));

  return (
    <nav className={`fixed top-0 left-0 right-0 z-[100] transition-all duration-500 ${scrolled ? 'py-3' : 'py-6'}`}>
      <div className={`max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 transition-all duration-500 ${scrolled ? 'scale-[0.98]' : 'scale-100'}`}>
        <div className={`glass-card rounded-[2rem] px-6 py-2.5 flex justify-between items-center shadow-2xl shadow-brand-dark/5 transition-all`}>
          <div className="flex items-center">
            <Link to="/" className="flex items-center space-x-3">
              <VizioniLogo />
              <div className="flex flex-col -space-y-1">
                <span className="text-lg font-black text-brand-dark tracking-tighter uppercase leading-none">Vizioni</span>
                <span className="text-[8px] font-black text-slate-400 uppercase tracking-[0.25em]">Rinor i Shalës</span>
              </div>
            </Link>
          </div>

          {/* Desktop Menu */}
          <div className="hidden md:flex items-center space-x-1">
            <Link to="/" className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${location.pathname === '/' ? 'text-brand-pink bg-brand-pink/5' : 'text-slate-600 hover:text-brand-pink'}`}>
              {t('nav.home')}
            </Link>

            <div className="relative group" onMouseEnter={() => setActiveDropdown('about')} onMouseLeave={() => setActiveDropdown(null)}>
              <button className={`flex items-center space-x-1 px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${isActive('/about') ? 'text-brand-pink bg-brand-pink/5' : 'text-slate-600 hover:text-brand-pink'}`}>
                <span>{t('nav.about')}</span>
                <ChevronDown className={`h-3 w-3 transition-transform duration-300 ${activeDropdown === 'about' ? 'rotate-180' : ''}`} />
              </button>
              <div className={`absolute left-0 mt-2 w-48 bg-white border border-slate-100 shadow-2xl rounded-[1.5rem] p-2 transition-all transform origin-top ${activeDropdown === 'about' ? 'opacity-100 scale-100 translate-y-0' : 'opacity-0 scale-95 pointer-events-none -translate-y-2'}`}>
                <Link to="/about/mission" className="flex items-center space-x-2 px-4 py-3 rounded-xl text-[9px] font-black text-slate-600 hover:bg-slate-50 hover:text-brand-pink uppercase tracking-widest transition-all">
                  <div className="w-1 h-1 rounded-full bg-brand-pink"></div>
                  <span>{t('nav.mission')}</span>
                </Link>
                <Link to="/about/staff" className="flex items-center space-x-2 px-4 py-3 rounded-xl text-[9px] font-black text-slate-600 hover:bg-slate-50 hover:text-brand-pink uppercase tracking-widest transition-all">
                  <div className="w-1 h-1 rounded-full bg-brand-lime"></div>
                  <span>{t('nav.staff')}</span>
                </Link>
              </div>
            </div>

            <Link to="/projects" className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${isActive('/projects') ? 'text-brand-cyan bg-brand-cyan/5' : 'text-slate-600 hover:text-brand-cyan'}`}>
              {t('nav.projects')}
            </Link>

            <Link to="/derdo" className={`flex items-center space-x-1.5 px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${isActive('/derdo') ? 'text-brand-orange bg-brand-orange/5' : 'text-slate-600 hover:text-brand-orange'}`}>
              <MessageSquare className="h-4 w-4" />
              <span>{t('nav.derdo')}</span>
            </Link>

            <div className="w-px h-5 bg-slate-100 mx-2"></div>

            <Link to="/join" className={`btn-vizioni flex items-center space-x-2 px-6 py-2.5 rounded-full text-[9px] font-black uppercase tracking-widest transition-all shadow-lg hover:shadow-brand-lime/20 ${isActive('/join') ? 'bg-brand-lime text-white' : 'bg-brand-dark text-white hover:bg-brand-lime'}`}>
              <UserPlus className="h-3.5 w-3.5" />
              <span>{t('nav.join')}</span>
            </Link>

            {user ? (
              <div className="flex items-center space-x-2 ml-4">
                {user.role === UserRole.ADMIN && (
                  <Link to="/admin" className="p-2.5 bg-brand-cyan/10 text-brand-cyan rounded-full hover:bg-brand-cyan hover:text-white transition-all">
                    <LayoutDashboard className="h-4 w-4" />
                  </Link>
                )}
                <button onClick={onLogout} className="p-2.5 bg-red-50 text-red-500 rounded-full hover:bg-red-500 hover:text-white transition-all">
                  <LogOut className="h-4 w-4" />
                </button>
              </div>
            ) : (
              <Link to="/login" className="ml-4 p-2.5 bg-slate-50 text-brand-dark rounded-full hover:bg-brand-pink hover:text-white transition-all">
                <LogIn className="h-4 w-4" />
              </Link>
            )}
          </div>

          <div className="md:hidden flex items-center">
            <button onClick={() => setIsOpen(!isOpen)} className="text-slate-500 p-2 bg-slate-50 rounded-xl">{isOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}</button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      <div className={`md:hidden fixed inset-0 z-[90] bg-white/95 backdrop-blur-xl transition-all duration-500 ${isOpen ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-full pointer-events-none'}`}>
        <div className="flex flex-col items-center justify-center h-full space-y-8 px-8">
           <Link to="/" className="text-4xl font-black uppercase tracking-tighter text-brand-dark" onClick={() => setIsOpen(false)}>{t('nav.home')}</Link>
           <Link to="/about/mission" className="text-4xl font-black uppercase tracking-tighter text-brand-pink" onClick={() => setIsOpen(false)}>{t('nav.about')}</Link>
           <Link to="/projects" className="text-4xl font-black uppercase tracking-tighter text-brand-cyan" onClick={() => setIsOpen(false)}>{t('nav.projects')}</Link>
           <Link to="/derdo" className="text-4xl font-black uppercase tracking-tighter text-brand-orange" onClick={() => setIsOpen(false)}>{t('nav.derdo')}</Link>
           <Link to="/join" className="px-12 py-5 bg-brand-lime text-white rounded-full text-xl font-black uppercase tracking-widest shadow-2xl" onClick={() => setIsOpen(false)}>{t('nav.join')}</Link>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
